Certainly! Below is an example of Depth-First Search (DFS) implemented in C++. This code uses both recursive and iterative approaches to traverse a graph represented using an adjacency list.

### Recursive Approach

```cpp
#include <iostream>
#include <vector>
#include <stack>

using namespace std;

class Graph {
private:
    int V; // Number of vertices
    vector<int> *adj; // Pointer to an array containing adjacency lists

public:
    Graph(int V) {
        this->V = V;
        adj = new vector<int>[V];
    }

    void addEdge(int v, int w) {
        adj[v].push_back(w); // Add w to v’s list.
    }

    void DFSUtil(int v, bool visited[]) {
        visited[v] = true;
        cout << v << " ";

        for (int i = 0; i < adj[v].size(); ++i)
            if (!visited[adj[v][i]])
                DFSUtil(adj[v][i], visited);
    }

    void DFS(int s) {
        bool *visited = new bool[V];
        for (int i = 0; i < V; i++)
            visited[i] = false;

        DFSUtil(s, visited);
    }
};

int main() {
    Graph g(4); // Create a graph with 4 vertices
    g.addEdge(0, 1);
    g.addEdge(0, 2);
    g.addEdge(1, 2);
    g.addEdge(2, 0);
    g.addEdge(2, 3);
    g.addEdge(3, 3);

    cout << "Depth First Traversal (starting from vertex 2): ";
    g.DFS(2);

    return 0;
}
```

### Iterative Approach

```cpp
#include <iostream>
#include <vector>
#include <stack>

using namespace std;

class Graph {
private:
    int V; // Number of vertices
    vector<int> *adj; // Pointer to an array containing adjacency lists

public:
    Graph(int V) {
        this->V = V;
        adj = new vector<int>[V];
    }

    void addEdge(int v, int w) {
        adj[v].push_back(w); // Add w to v’s list.
    }

    void DFS(int s) {
        bool *visited = new bool[V];
        for (int i = 0; i < V; i++)
            visited[i] = false;

        stack<int> stack;
        stack.push(s);

        while (!stack.empty()) {
            s = stack.top();
            stack.pop();

            if (!visited[s]) {
                cout << s << " ";
                visited[s] = true;
            }

            for (int i = adj[s].size() - 1; i >= 0; --i) {
                int v = adj[s][i];
                if (!visited[v])
                    stack.push(v);
            }
        }
    }
};

int main() {
    Graph g(4); // Create a graph with 4 vertices
    g.addEdge(0, 1);
    g.addEdge(0, 2);
    g.addEdge(1, 2);
    g.addEdge(2, 0);
    g.addEdge(2, 3);
    g.addEdge(3, 3);

    cout << "Depth First Traversal (starting from vertex 2): ";
    g.DFS(2);

    return 0;
}
```

### Explanation

1. **Graph Class**:
   - `V`: Number of vertices.
   - `adj`: An array of vectors to represent the adjacency list.

2. **addEdge(int v, int w)**: Adds an edge from vertex `v` to vertex `w`.

3. **DFSUtil(int v, bool visited[])**: A helper function for DFS using recursion. It marks the current node as visited and prints it. Then, it recursively visits all the adjacent vertices that haven't been visited yet.

4. **DFS(int s)**: The main DFS function. It initializes a boolean array to keep track of visited nodes and calls `DFSUtil` starting from vertex `s`.

5. **Iterative DFS**:
   - Uses a stack to simulate the call stack used in recursion.
   - Pushes the start vertex onto the stack and processes it until the stack is empty.

Both implementations will produce the same output for a given graph, showing the depth-first traversal starting from a specified vertex.

